targets.rawSql:
SELECT count(DISTINCT d.target_name)::bigint AS targets
FROM monitoring.db_port_blackbox_daily_kpi d
WHERE d.period_start BETWEEN $__timeFrom()::date AND $__timeTo()::date AND ('$environment' = '%' OR d.environment = '$environment') AND ('$db_type' = '%' OR d.db_type = '$db_type') AND ('$target' = '%' OR d.target_name = '$target') AND ('$criticality' = '%' OR coalesce(d.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(d.team, 'unassigned') = '$team');

SELECT coalesce(sum(d.down_probes), 0)::bigint AS down_target_minutes
FROM monitoring.db_port_blackbox_daily_kpi d
WHERE d.period_start BETWEEN $__timeFrom()::date AND $__timeTo()::date AND ('$environment' = '%' OR d.environment = '$environment') AND ('$db_type' = '%' OR d.db_type = '$db_type') AND ('$target' = '%' OR d.target_name = '$target') AND ('$criticality' = '%' OR coalesce(d.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(d.team, 'unassigned') = '$team');

SELECT count(*)::bigint AS incidents_started
FROM monitoring.db_port_blackbox_downtime_events e
WHERE e.down_start::date BETWEEN $__timeFrom()::date AND $__timeTo()::date AND ('$environment' = '%' OR e.environment = '$environment') AND ('$db_type' = '%' OR e.db_type = '$db_type') AND ('$target' = '%' OR e.target_name = '$target') AND ('$criticality' = '%' OR coalesce(e.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(e.team, 'unassigned') = '$team');

SELECT coalesce(round(avg(extract(epoch FROM e.down_end - e.down_start) / 60.0)::numeric, 2), 0) AS mttr_minutes
FROM monitoring.db_port_blackbox_downtime_events e
WHERE e.down_start::date BETWEEN $__timeFrom()::date AND $__timeTo()::date AND e.down_end IS NOT NULL AND ('$environment' = '%' OR e.environment = '$environment') AND ('$db_type' = '%' OR e.db_type = '$db_type') AND ('$target' = '%' OR e.target_name = '$target') AND ('$criticality' = '%' OR coalesce(e.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(e.team, 'unassigned') = '$team');

SELECT coalesce(round(sum(d.latency_ms_sum) / nullif(sum(d.latency_ms_count), 0), 2), 0) AS avg_latency_ms
FROM monitoring.db_port_blackbox_daily_kpi d
WHERE d.period_start BETWEEN $__timeFrom()::date AND $__timeTo()::date AND ('$environment' = '%' OR d.environment = '$environment') AND ('$db_type' = '%' OR d.db_type = '$db_type') AND ('$target' = '%' OR d.target_name = '$target') AND ('$criticality' = '%' OR coalesce(d.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(d.team, 'unassigned') = '$team');

WITH bounds AS (
  SELECT $__timeFrom()::date AS from_date, $__timeTo()::date AS to_date
), prior_data AS (
  SELECT count(*) > 0 AS available
  FROM monitoring.db_port_blackbox_daily_kpi d CROSS JOIN bounds b
  WHERE d.period_start BETWEEN (b.from_date - interval '1 year')::date AND (b.to_date - interval '1 year')::date AND ('$environment' = '%' OR d.environment = '$environment') AND ('$db_type' = '%' OR d.db_type = '$db_type') AND ('$target' = '%' OR d.target_name = '$target') AND ('$criticality' = '%' OR coalesce(d.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(d.team, 'unassigned') = '$team')
), incidents AS (
  SELECT count(*) FILTER (WHERE e.down_start::date BETWEEN b.from_date AND b.to_date)::bigint AS current_incidents, count(*) FILTER (WHERE e.down_start::date BETWEEN (b.from_date - interval '1 year')::date AND (b.to_date - interval '1 year')::date)::bigint AS previous_incidents
  FROM monitoring.db_port_blackbox_downtime_events e CROSS JOIN bounds b
  WHERE ('$environment' = '%' OR e.environment = '$environment') AND ('$db_type' = '%' OR e.db_type = '$db_type') AND ('$target' = '%' OR e.target_name = '$target') AND ('$criticality' = '%' OR coalesce(e.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(e.team, 'unassigned') = '$team')
)
SELECT CASE WHEN p.available THEN (i.current_incidents - i.previous_incidents)::double precision END AS incidents_yoy
FROM incidents i CROSS JOIN prior_data p;

SELECT round(sum(d.down_probes)::numeric / nullif(sum(d.probes)::numeric * (1 - ${sla:raw} / 100.0), 0) * 100, 2)::double precision AS error_budget_used_pct
FROM monitoring.db_port_blackbox_daily_kpi d
WHERE d.period_start BETWEEN $__timeFrom()::date AND $__timeTo()::date AND ('$environment' = '%' OR d.environment = '$environment') AND ('$db_type' = '%' OR d.db_type = '$db_type') AND ('$target' = '%' OR d.target_name = '$target') AND ('$criticality' = '%' OR coalesce(d.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(d.team, 'unassigned') = '$team');

WITH bounds AS (
  SELECT $__timeFrom()::date AS from_date, $__timeTo()::date AS to_date
), scoped_history AS (
  SELECT d.*
  FROM monitoring.db_port_blackbox_daily_kpi d
  WHERE ('$environment' = '%' OR d.environment = '$environment') AND ('$db_type' = '%' OR d.db_type = '$db_type') AND ('$target' = '%' OR d.target_name = '$target') AND ('$criticality' = '%' OR coalesce(d.criticality, 'unassigned') = '$criticality') AND ('$team' = '%' OR coalesce(d.team, 'unassigned') = '$team')
)
SELECT min(period_start) AS history_start, max(period_start) AS history_end, max(last_probe_at) AS latest_probe_at, (max(period_start) - min(period_start) + 1)::bigint AS history_calendar_days, count(DISTINCT target_name)::bigint AS targets_in_history, coalesce(sum(probes) FILTER (WHERE period_start BETWEEN b.from_date AND b.to_date), 0)::bigint AS selected_observed_target_minutes, CASE WHEN count(*) FILTER (WHERE period_start BETWEEN (b.from_date - interval '1 year')::date AND (b.to_date - interval '1 year')::date) > 0 THEN 'AVAILABLE' ELSE 'NOT AVAILABLE' END AS previous_year_data
FROM scoped_history CROSS JOIN bounds b
GROUP BY b.from_date, b.to_date;
